-- امسح القديم لو موجود عشان تبدأ نظيف
DELETE FROM users WHERE role = 'rep';
DELETE FROM users WHERE role = 'supervisor';

-- ── المنسقون (40 منسق من الإكسيل) ───────────────────────────

-- ── المشرفون والمديرون ────────────────────────────────────────

-- ✅ تحقق من النتيجة
SELECT role, count(*) as العدد FROM users GROUP BY role ORDER BY role;
